from flask import Flask, request, jsonify
import pyotp
from werkzeug.security import check_password_hash

app = Flask(__name__)

# Sample user database (replace with a proper database)
users = {
    'user1': {'password': 'hashed_password', 'mfa_enabled': True}
}

def verify_password(username, password):
    if username in users:
        return check_password_hash(users[username]['password'], password)
    return False

def get_otp_secret(username):
    if username in users and users[username]['mfa_enabled']:
        return pyotp.random_base32()
    return None

@app.route('/api/login', methods=['POST'])
def login():
    data = request.json
    username, password = data['username'], data['password']
    
    if not verify_password(username, password):
        return jsonify({'message': 'Invalid credentials'}), 401
    
    otp_secret = get_otp_secret(username)
    
    if otp_secret:
        # Prompt for OTP (replace with a proper UI component or API call)
        print("Enter your MFA code:")
        user_input = input()
        
        totp = pyotp.TOTP(otp_secret).now()
        
        if int(user_input) != totp:
            return jsonify({'message': 'Invalid OTP'}), 401
    
    # Return a JWT token for the user
    import jwt
    payload = {'username': username}
    return jsonify(jwt.encode(payload, secret='secret_key', algorithm='HS256').decode('utf-8'))

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    username, password = data['username'], data['password']
    
    if not verify_password(username, password):
        return jsonify({'message': 'Invalid credentials'}), 401
    
    # Return a JWT token for the user without MFA check
    import jwt
    payload = {'username': username}
    return jsonify(jwt.encode(payload, secret='secret_key', algorithm='HS256').decode('utf-8'))

if __name__ == '__main__':
    app.run(debug=True)